Una tabla hash (o diccionario) es una estructura de datos que asocia llaves con valores, permitiendo acceso casi instantáneo a los datos. Funciona como un archivador donde cada documento tiene una etiqueta y sabes exactamente en qué cajón buscar.

Concepto fundamental:
- Usa una función hash que convierte la llave en un índice
- Almacena el par (llave, valor) en ese índice
- Permite operaciones en tiempo O(1) promedio

Implementación básica en Python:
python
class TablaHash:
 def __init__(self, capacidad=10):
 self.capacidad = capacidad
 self.tabla = [[] for _ in range(capacidad)] # Lista de listas para manejar colisiones
 self.tamaño = 0

 def _hash(self, llave):
 """Función hash simple para strings"""
 if isinstance(llave, str):
 # Suma de valores ASCII
 return sum(ord(c) for c in llave) % self.capacidad
 # Para números, usar módulo
 return hash(llave) % self.capacidad

 def insertar(self, llave, valor):
 """Inserta o actualiza un par llave-valor"""
 indice = self._hash(llave)

 # Buscar si la llave ya existe
 for i, (k, v) in enumerate(self.tabla[indice]):
 if k == llave:
 self.tabla[indice][i] = (llave, valor) # Actualizar
 return

 # Si no existe, agregar nueva
 self.tabla[indice].append((llave, valor))
 self.tamaño += 1

 # Opcional: redimensionar si factor de carga > 0.7
 if self.tamaño / self.capacidad > 0.7:
 self._redimensionar()

 def obtener(self, llave):
 """Obtiene el valor asociado a una llave"""
 indice = self._hash(llave)

 for k, v in self.tabla[indice]:
 if k == llave:
 return v

 raise KeyError(f"Llave '{llave}' no encontrada")

 def eliminar(self, llave):
 """Elimina un par llave-valor"""
 indice = self._hash(llave)

 for i, (k, v) in enumerate(self.tabla[indice]):
 if k == llave:
 del self.tabla[indice][i]
 self.tamaño -= 1
 return

 raise KeyError(f"Llave '{llave}' no encontrada")

 def _redimensionar(self):
 """Redimensiona la tabla cuando el factor de carga es alto"""
 vieja_tabla = self.tabla
 self.capacidad *= 2
 self.tabla = [[] for _ in range(self.capacidad)]
 self.tamaño = 0

 for bucket in vieja_tabla:
 for llave, valor in bucket:
 self.insertar(llave, valor)

 def __contains__(self, llave):
 try:
 self.obtener(llave)
 return True
 except KeyError:
 return False

 def __str__(self):
 elementos = []
 for bucket in self.tabla:
 for llave, valor in bucket:
 elementos.append(f"{llave}: {valor}")
 return "{" + ", ".join(elementos) + "}"

# Ejemplo de uso
