javascript
class TablaHash {
 constructor(capacidad = 10) {
 this.capacidad = capacidad;
 this.tabla = new Array(capacidad).fill(null).map(() => []);
 this.tamaño = 0;
 }

 _hash(llave) {
 if (typeof llave === 'string') {
 let hash = 0;
 for (let i = 0; i < llave.length; i++) {
 hash = (hash + llave.charCodeAt(i)) % this.capacidad;
 }
 return hash;
 }
 // Para números u objetos, usar el hash nativo
 return String(llave).split('').reduce((a, b) => {
 a = ((a << 5) - a) + b.charCodeAt(0);
 return a & a;
 }, 0) % this.capacidad;
 }

 set(llave, valor) {
 const indice = this._hash(llave);
 const bucket = this.tabla[indice];

 for (let i = 0; i < bucket.length; i++) {
 if (bucket[i][0] === llave) {
 bucket[i][1] = valor; // Actualizar
 return;
 }
 }

 bucket.push([llave, valor]);
 this.tamaño++;

 // Redimensionar si es necesario
 if (this.tamaño / this.capacidad > 0.7) {
 this._redimensionar();
 }
 }

 get(llave) {
 const indice = this._hash(llave);
 const bucket = this.tabla[indice];

 for (const [k, v] of bucket) {
 if (k === llave) return v;
 }
 return undefined;
 }

 delete(llave) {
 const indice = this._hash(llave);
 const bucket = this.tabla[indice];

 for (let i = 0; i < bucket.length; i++) {
 if (bucket[i][0] === llave) {
 bucket.splice(i, 1);
 this.tamaño--;
 return true;
 }
 }
 return false;
 }

 _redimensionar() {
 const viejaTabla = this.tabla;
 this.capacidad *= 2;
 this.tabla = new Array(this.capacidad).fill(null).map(() => []);
 this.tamaño = 0;

 for (const bucket of viejaTabla) {
 for (const [llave, valor] of bucket) {
 this.set(llave, valor);
 }
 }
 }

 has(llave) {
 return this.get(llave) !== undefined;
 }
}

// Ejemplo de uso
const usuarios = new TablaHash();
usuarios.set('user1', { nombre: 'Juan', edad: 30 });
usuarios.set('user2', { nombre: 'María', edad: 25 });
console.log(usuarios.get('user1')); // { nombre: 'Juan', edad: 30 }


