public class Factorial {

 /**
 * Calcula el factorial de forma recursiva
 * @param n número entero no negativo
 * @return factorial de n
 * @throws IllegalArgumentException si n es negativo
 */
 public static long factorialRecursivo(int n) {
 if (n < 0) {
 throw new IllegalArgumentException("n no puede ser negativo");
 }
 if (n == 0 || n == 1) {
 return 1;
 }
 return n * factorialRecursivo(n - 1);
 }

 /**
 * Versión iterativa (evita desbordamiento de pila)
 */
 public static long factorialIterativo(int n) {
 if (n < 0) {
 throw new IllegalArgumentException("n no puede ser negativo");
 }

 long resultado = 1;
 for (int i = 2; i <= n; i++) {
 resultado *= i;
 }
 return resultado;
 }

 /**
 * Versión para números grandes usando BigInteger
 */
 public static BigInteger factorialBigInteger(int n) {
 if (n < 0) {
 throw new IllegalArgumentException("n no puede ser negativo");
 }

 BigInteger resultado = BigInteger.ONE;
 for (int i = 2; i <= n; i++) {
 resultado = resultado.multiply(BigInteger.valueOf(i));
 }
 return resultado;
 }

 public static void main(String[] args) {
 System.out.println("Factorial de 5: " + factorialIterativo(5)); // 120
 System.out.println("Factorial de 20: " + factorialBigInteger(20));
 }
}


