 * Calcula el factorial de un número
 * @param {number} n - Número entero no negativo
 * @returns {number|bigint} Factorial de n
 * @throws {Error} Si n no es válido
 */
function factorial(n) {
 // Validaciones
 if (!Number.isInteger(n)) {
 throw new Error('n debe ser un número entero');
 }
 if (n < 0) {
 throw new Error('El factorial no está definido para números negativos');
 }
 if (n > 20) {
 console.warn('Para n > 20, usar BigInt para evitar pérdida de precisión');
 }

 // Casos base
 if (n === 0 || n === 1) return 1;

 // Cálculo iterativo
 let resultado = 1;
 for (let i = 2; i <= n; i++) {
 resultado *= i;
 }
 return resultado;
}

// Versión con BigInt para números grandes
function factorialBigInt(n) {
 if (!Number.isInteger(n) || n < 0) {
 throw new Error('n debe ser un entero no negativo');
 }

 let resultado = 1n;
 for (let i = 2n; i <= BigInt(n); i++) {
 resultado *= i;
 }
 return resultado;
}

// Versión recursiva con tail recursion
function factorialTail(n, acumulador = 1) {
 if (n < 0) throw new Error('n no puede ser negativo');
 if (n === 0 || n === 1) return acumulador;
 return factorialTail(n - 1, n * acumulador);
}


