## 2. Implementación desde cero

java
import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;

public class TablaHashImplementacion<K, V> {

 // Clase interna para los pares llave-valor
 private static class Entrada<K, V> {
 K llave;
 V valor;

 Entrada(K llave, V valor) {
 this.llave = llave;
 this.valor = valor;
 }
 }

 private LinkedList<Entrada<K, V>>[] buckets;
 private int capacidad;
 private int tamaño;
 private static final double FACTOR_CARGA = 0.75;

 @SuppressWarnings("unchecked")
 public TablaHashImplementacion() {
 this(16); // Capacidad inicial por defecto
 }

 @SuppressWarnings("unchecked")
 public TablaHashImplementacion(int capacidadInicial) {
 this.capacidad = capacidadInicial;
 this.buckets = new LinkedList[capacidad];
 this.tamaño = 0;

 for (int i = 0; i < capacidad; i++) {
 buckets[i] = new LinkedList<>();
 }
 }

 // Función hash mejorada
 private int hash(K llave) {
 if (llave == null) return 0;

 int hashCode = llave.hashCode();
 // Mezclar bits para mejor distribución
 hashCode = hashCode ^ (hashCode >>> 16);
 return Math.abs(hashCode) % capacidad;
 }

 // Insertar o actualizar
 public void put(K llave, V valor) {
 if (llave == null) {
 throw new IllegalArgumentException("La llave no puede ser null");
 }

 int indice = hash(llave);
 LinkedList<Entrada<K, V>> bucket = buckets[indice];

 // Buscar si la llave ya existe
 for (Entrada<K, V> entrada : bucket) {
 if (entrada.llave.equals(llave)) {
 entrada.valor = valor; // Actualizar
 return;
 }
 }

 // Si no existe, agregar nueva entrada
 bucket.add(new Entrada<>(llave, valor));
 tamaño++;

 // Redimensionar si es necesario
 if ((double) tamaño / capacidad > FACTOR_CARGA) {
 redimensionar();
 }
 }

 // Obtener valor
 public V get(K llave) {
 int indice = hash(llave);
 LinkedList<Entrada<K, V>> bucket = buckets[indice];

 for (Entrada<K, V> entrada : bucket) {
 if (entrada.llave.equals(llave)) {
 return entrada.valor;
 }
 }

 return null; // No encontrado
 }

 // Eliminar
 public V remove(K llave) {
 int indice = hash(llave);
 LinkedList<Entrada<K, V>> bucket = buckets[indice];

 for (Entrada<K, V> entrada : bucket) {
 if (entrada.llave.equals(llave)) {
 bucket.remove(entrada);
 tamaño--;
 return entrada.valor;
 }
 }

 return null;
 }

 // Verificar si contiene llave
 public boolean containsKey(K llave) {
 return get(llave) != null;
 }

 // Obtener tamaño
 public int size() {
 return tamaño;
 }

 // Verificar si está vacía
 public boolean isEmpty() {
 return tamaño == 0;
 }

 // Redimensionar cuando el factor de carga es alto
 @SuppressWarnings("unchecked")
 private void redimensionar() {
 int nuevaCapacidad = capacidad * 2;
 LinkedList<Entrada<K, V>>[] nuevosBuckets = new LinkedList[nuevaCapacidad];

 for (int i = 0; i < nuevaCapacidad; i++) {
 nuevosBuckets[i] = new LinkedList<>();
 }

 // Re-hashear todas las entradas
 for (LinkedList<Entrada<K, V>> bucket : buckets) {
 for (Entrada<K, V> entrada : bucket) {
 int nuevoIndice = Math.abs(entrada.llave.hashCode() ^ 
 (entrada.llave.hashCode() >>> 16)) % nuevaCapacidad;
 nuevosBuckets[nuevoIndice].add(entrada);
 }
 }

 this.buckets = nuevosBuckets;
 this.capacidad = nuevaCapacidad;
 }

 // Obtener todas las llaves
 public List<K> keys() {
 List<K> llaves = new ArrayList<>();
 for (LinkedList<Entrada<K, V>> bucket : buckets) {
 for (Entrada<K, V> entrada : bucket) {
 llaves.add(entrada.llave);
 }
 }
 return llaves;
 }

 // Obtener todos los valores
 public List<V> values() {
 List<V> valores = new ArrayList<>();
 for (LinkedList<Entrada<K, V>> bucket : buckets) {
 for (Entrada<K, V> entrada : bucket) {
 valores.add(entrada.valor);
 }
 }
 return valores;
 }

 // Estadísticas de la tabla
 public void imprimirEstadisticas() {
 System.out.println("=== Estadísticas de la Tabla Hash ===");
 System.out.println("Capacidad: " + capacidad);
 System.out.println("Tamaño: " + tamaño);
 System.out.println("Factor de carga: " + String.format("%.2f", (double) tamaño / capacidad));

 int bucketsVacios = 0;
 int maxBucketSize = 0;

 for (int i = 0; i < buckets.length; i++) {
 int bucketSize = buckets[i].size();
 if (bucketSize == 0) {
 bucketsVacios++;
 }
 maxBucketSize = Math.max(maxBucketSize, bucketSize);
 }

 System.out.println("Buckets vacíos: " + bucketsVacios);
 System.out.println("Tamaño máximo de bucket: " + maxBucketSize);
 System.out.println("Distribución:");

 int[] distribucion = new int[maxBucketSize + 1];
 for (LinkedList<Entrada<K, V>> bucket : buckets) {
 distribucion[bucket.size()]++;
 }

 for (int i = 0; i <= maxBucketSize; i++) {
 if (distribucion[i] > 0) {
 System.out.println(" Buckets con " + i + " elementos: " + distribucion[i]);
 }
 }
 }

 // Método toString
 @Override
 public String toString() {
 StringBuilder sb = new StringBuilder("{");
 boolean primero = true;

 for (LinkedList<Entrada<K, V>> bucket : buckets) {
 for (Entrada<K, V> entrada : bucket) {
 if (!primero) {
 sb.append(", ");
 }
 sb.append(entrada.llave).append("=").append(entrada.valor);
 primero = false;
 }
 }

 return sb.append("}").toString();
 }
}


