¿Quieres implementar la búsqueda de palabras?

Un árbol binario es una estructura de datos jerárquica donde cada nodo tiene como máximo dos hijos: izquierdo y derecho. Es como un organigrama de empresa donde cada persona puede tener hasta dos subordinados directos.

**Conceptos fundamentales:**
- **Raíz:** Nodo superior del árbol
- **Hojas:** Nodos sin hijos
- **Altura:** Distancia máxima desde la raíz hasta una hoja
- **Nivel:** Conjunto de nodos a la misma profundidad

**Implementación básica en Python:**

```python
class Nodo:
    def __init__(self, valor):
        self.valor = valor
        self.izquierdo = None
        self.derecho = None

class ArbolBinario:
    def __init__(self):
        self.raiz = None

    def insertar(self, valor):
        if not self.raiz:
            self.raiz = Nodo(valor)
        else:
            self._insertar_recursivo(self.raiz, valor)

    def _insertar_recursivo(self, nodo, valor):
        # Inserción simple (no es BST, solo para demostración)
        if not nodo.izquierdo:
            nodo.izquierdo = Nodo(valor)
        elif not nodo.derecho:
            nodo.derecho = Nodo(valor)
        else:
            # Si ambos hijos existen, insertar en el subárbol izquierdo
            self._insertar_recursivo(nodo.izquierdo, valor)

    def recorrido_preorden(self, nodo=None, resultado=None):
        """Raíz -> Izquierdo -> Derecho"""
        if resultado is None:
            resultado = []
        if nodo is None:
            nodo = self.raiz

        if nodo:
            resultado.append(nodo.valor)
            self.recorrido_preorden(nodo.izquierdo, resultado)
            self.recorrido_preorden(nodo.derecho, resultado)
        return resultado

    def recorrido_inorden(self, nodo=None, resultado=None):
        """Izquierdo -> Raíz -> Derecho"""
        if resultado is None:
            resultado = []
        if nodo is None:
            nodo = self.raiz

        if nodo:
            self.recorrido_inorden(nodo.izquierdo, resultado)
            resultado.append(nodo.valor)
            self.recorrido_inorden(nodo.derecho, resultado)
        return resultado

    def recorrido_postorden(self, nodo=None, resultado=None):
        """Izquierdo -> Derecho -> Raíz"""
        if resultado is None:
            resultado = []
        if nodo is None:
            nodo = self.raiz

        if nodo:
            self.recorrido_postorden(nodo.izquierdo, resultado)
            self.recorrido_postorden(nodo.derecho, resultado)
            resultado.append(nodo.valor)
        return resultado

    def recorrido_por_niveles(self):
        """BFS - Recorrido por niveles usando cola"""
        if not self.raiz:
            return []

        resultado = []
        cola = [self.raiz]

        while cola:
            nivel_actual = []
            nivel_size = len(cola)

            for _ in range(nivel_size):
                nodo = cola.pop(0)
                nivel_actual.append(nodo.valor)

                if nodo.izquierdo:
                    cola.append(nodo.izquierdo)
                if nodo.derecho:
                    cola.append(nodo.derecho)

            resultado.append(nivel_actual)

        return resultado

    def altura(self, nodo=None):
        if nodo is None:
            nodo = self.raiz
        if not nodo:
            return 0

        altura_izq = self.altura(nodo.izquierdo)
        altura_der = self.altura(nodo.derecho)
        return max(altura_izq, altura_der) + 1

    def contar_nodos(self, nodo=None):
        if nodo is None:
            nodo = self.raiz
        if not nodo:
            return 0

        return 1 + self.contar_nodos(nodo.izquierdo) + self.contar_nodos(nodo.derecho)

    def es_hoja(self, nodo):
        return nodo and not nodo.izquierdo and not nodo.derecho

    def imprimir_arbol(self, nodo=None, nivel=0, prefijo="Raíz: "):
        if nodo is None:
            nodo = self.raiz
        if nodo:
            print("  " * nivel + prefijo + str(nodo.valor))
            if nodo.izquierdo or nodo.derecho:
                self.imprimir_arbol(nodo.izquierdo, nivel + 1, "Izq: ")
                self.imprimir_arbol(nodo.derecho, nivel + 1, "Der: ")

# Ejemplo de uso
arbol = ArbolBinario()
valores = [1, 2, 3, 4, 5, 6, 7]
for v in valores:
    arbol.insertar(v)

print("Estructura del árbol:")
arbol.imprimir_arbol()

print("\nRecorridos:")
print(f"Preorden: {arbol.recorrido_preorden()}")
print(f"Inorden: {arbol.recorrido_inorden()}")
print(f"Postorden: {arbol.recorrido_postorden()}")
print(f"Por niveles: {arbol.recorrido_por_niveles()}")

print(f"\nAltura del árbol: {arbol.altura()}")
print(f"Número de nodos: {arbol.contar_nodos()}")
```

**Tipos de árboles binarios importantes:**

```python
class ArbolBinarioBusqueda:
    """BST: Binary Search Tree"""
    def __init__(self):
        self.raiz = None

    def insertar(self, valor):
        if not self.raiz:
            self.raiz = NodoBST(valor)
        else:
            self._insertar_recursivo(self.raiz, valor)

    def _insertar_recursivo(self, nodo, valor):
        if valor < nodo.valor:
            if nodo.izquierdo:
                self._insertar_recursivo(nodo.izquierdo, valor)
            else:
                nodo.izquierdo = NodoBST(valor)
        else:
            if nodo.derecho:
                self._insertar_recursivo(nodo.derecho, valor)
            else:
                nodo.derecho = NodoBST(valor)

    def buscar(self, valor):
        return self._buscar_recursivo(self.raiz, valor)

    def _buscar_recursivo(self, nodo, valor):
        if not nodo or nodo.valor == valor:
            return nodo
        if valor < nodo.valor:
            return self._buscar_recursivo(nodo.izquierdo, valor)
        return self._buscar_recursivo(nodo.derecho, valor)

class NodoBST(Nodo):
    pass  # Hereda la misma estructura
```

**Complejidades:**
- Búsqueda en árbol balanceado: O(log n)
- Inserción en árbol balanceado: O(log n)
- Recorridos completos: O(n)
- Altura: O(n) para calcularla

**Aplicaciones comunes:**
1. **BST:** Búsqueda eficiente de datos
2. **Heap:** Colas de prioridad
3. **Árboles de expresión:** Evaluación de expresiones matemáticas
4. **Árboles de decisión:** Machine Learning
5. **Sintaxis abstracta:** Compiladores

