Merge Sort es un algoritmo de ordenamiento eficiente basado en la técnica de divide y vencerás. Divide el array en mitades, las ordena recursivamente y luego las combina. Es uno de los algoritmos más importantes por su rendimiento predecible O(n log n).

Implementación en JavaScript:

javascript
class MergeSort {
 // Versión principal que ordena el array
 static sort(arr) {
 // Crear una copia para no modificar el original
 const arrayCopy = [...arr];
 this.mergeSort(arrayCopy, 0, arrayCopy.length - 1);
 return arrayCopy;
 }

 // Método recursivo principal
 static mergeSort(arr, left, right) {
 if (left < right) {
 // Encontrar el punto medio
 const mid = Math.floor((left + right) / 2);

 // Ordenar las dos mitades recursivamente
 this.mergeSort(arr, left, mid);
 this.mergeSort(arr, mid + 1, right);

 // Combinar las mitades ordenadas
 this.merge(arr, left, mid, right);
 }
 }

 // Método para combinar dos subarrays ordenados
 static merge(arr, left, mid, right) {
 // Crear subarrays temporales
 const leftArray = [];
 const rightArray = [];

 // Copiar datos a los arrays temporales
 for (let i = left; i <= mid; i++) {
 leftArray.push(arr[i]);
 }
 for (let i = mid + 1; i <= right; i++) {
 rightArray.push(arr[i]);
 }

 // Índices para recorrer los arrays temporales y el principal
 let i = 0; // Índice para leftArray
 let j = 0; // Índice para rightArray
 let k = left; // Índice para el array principal

 // Mezclar los arrays temporales en el principal
 while (i < leftArray.length && j < rightArray.length) {
 if (leftArray[i] <= rightArray[j]) {
 arr[k] = leftArray[i];
 i++;
 } else {
 arr[k] = rightArray[j];
 j++;
 }
 k++;
 }

 // Copiar elementos restantes de leftArray
 while (i < leftArray.length) {
 arr[k] = leftArray[i];
 i++;
 k++;
 }

 // Copiar elementos restantes de rightArray
 while (j < rightArray.length) {
 arr[k] = rightArray[j];
 j++;
 k++;
 }
 }

 // Versión más concisa que retorna un nuevo array
 static mergeSortFunctional(arr) {
 if (arr.length <= 1) return arr;

 const mid = Math.floor(arr.length / 2);
 const left = this.mergeSortFunctional(arr.slice(0, mid));
 const right = this.mergeSortFunctional(arr.slice(mid));

 return this.mergeFunctional(left, right);
 }

 static mergeFunctional(left, right) {
 const result = [];
 let i = 0, j = 0;

 while (i < left.length && j < right.length) {
 if (left[i] <= right[j]) {
 result.push(left[i]);
 i++;
 } else {
 result.push(right[j]);
 j++;
 }
 }

 // Agregar elementos restantes
 return [...result, ...left.slice(i), ...right.slice(j)];
 }

 // Versión in-place con optimización de memoria
 static mergeSortInPlace(arr, left = 0, right = arr.length - 1) {
 if (left < right) {
 const mid = Math.floor((left + right) / 2);

 this.mergeSortInPlace(arr, left, mid);
 this.mergeSortInPlace(arr, mid + 1, right);

 this.mergeInPlace(arr, left, mid, right);
 }
 return arr;
 }

 static mergeInPlace(arr, left, mid, right) {
 let start2 = mid + 1;

 // Si el último elemento de la izquierda es <= primer elemento de la derecha
 // entonces los arrays ya están ordenados
 if (arr[mid] <= arr[start2]) {
 return;
 }

 // Mover elementos mientras haya desorden
 while (left <= mid && start2 <= right) {
 if (arr[left] <= arr[start2]) {
 left++;
 } else {
 const value = arr[start2];
 let index = start2;

 // Desplazar elementos a la derecha
 while (index !== left) {
 arr[index] = arr[index - 1];
 index--;
 }
 arr[left] = value;

 // Actualizar todos los índices
 left++;
 mid++;
 start2++;
 }
 }
 }

 // Versión para objetos con propiedad específica
 static sortByProperty(arr, property) {
 const compare = (a, b) => a[property] - b[property];
 return this.mergeSortFunctional(arr, compare);
 }

 // Versión con función de comparación personalizada
 static sortWithCompare(arr, compareFn) {
 if (arr.length <= 1) return arr;

 const mid = Math.floor(arr.length / 2);
 const left = this.sortWithCompare(arr.slice(0, mid), compareFn);
 const right = this.sortWithCompare(arr.slice(mid), compareFn);

 return this.mergeWithCompare(left, right, compareFn);
 }

 static mergeWithCompare(left, right, compareFn) {
 const result = [];
 let i = 0, j = 0;

 while (i < left.length && j < right.length) {
 if (compareFn(left[i], right[j]) <= 0) {
 result.push(left[i]);
 i++;
 } else {
 result.push(right[j]);
 j++;
 }
 }

 return [...result, ...left.slice(i), ...right.slice(j)];
 }
}

