Un Binary Search Tree (BST) es una estructura de datos donde cada nodo tiene a lo sumo dos hijos, y el hijo izquierdo es menor que el nodo padre, mientras que el hijo derecho es mayor.

**Implementación completa:**
```java
class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

class BST {
    TreeNode root;

    void insert(int val) {
        root = insertRec(root, val);
    }

    TreeNode insertRec(TreeNode node, int val) {
        if (node == null) return new TreeNode(val);
        if (val < node.val) node.left = insertRec(node.left, val);
        else if (val > node.val) node.right = insertRec(node.right, val);
        return node;
    }

    boolean search(int val) {
        return searchRec(root, val);
    }

    boolean searchRec(TreeNode node, int val) {
        if (node == null) return false;
        if (node.val == val) return true;
        return val < node.val ? searchRec(node.left, val) : searchRec(node.right, val);
    }
}
```

**Complejidad:**
- Tiempo: O(h) donde h es la altura del árbol.
- Espacio: O(n) para almacenar nodos.

**Consejo:** El rendimiento depende de la forma del árbol; puede degenerar a O(n).

¿Quieres implementar eliminación de nodos?

BFS (Breadth-First Search) o búsqueda en anchura es un algoritmo para recorrer o buscar en grafos que explora todos los vecinos de un nodo antes de moverse al siguiente nivel. Es como una onda expansiva: primero visitas todos los nodos a distancia 1, luego a distancia 2, y así sucesivamente.

Analogía: Imagina que quieres encontrar a todas las personas que conocen a tu amigo en una red social. Primero preguntas a sus amigos directos, luego a los amigos de esos amigos, etc.

## Implementación en Python

python
from collections import deque

class Grafo:
 def __init__(self):
 self.lista_adyacencia = {}

 def agregar_vertice(self, vertice):
 if vertice not in self.lista_adyacencia:
 self.lista_adyacencia[vertice] = []

 def agregar_arista(self, u, v, dirigido=False):
 """Agrega una arista entre u y v"""
 self.agregar_vertice(u)
 self.agregar_vertice(v)

 self.lista_adyacencia[u].append(v)
 if not dirigido:
 self.lista_adyacencia[v].append(u)

 def bfs(self, inicio):
 """Recorrido BFS completo desde el nodo inicio"""
 visitados = set()
 cola = deque([inicio])
 recorrido = []
 distancias = {inicio: 0}
 padres = {inicio: None}

 visitados.add(inicio)

 print(f"Iniciando BFS desde {inicio}")
 nivel_actual = 0

 while cola:
 vertice = cola.popleft()
 recorrido.append(vertice)

 # Detectar cambio de nivel para mostrar
 if distancias[vertice] > nivel_actual:
 nivel_actual = distancias[vertice]
 print(f"\nNivel {nivel_actual}:")

 print(f" Visitando {vertice} (distancia {distancias[vertice]})")

 for vecino in self.lista_adyacencia[vertice]:
 if vecino not in visitados:
 visitados.add(vecino)
 cola.append(vecino)
 distancias[vecino] = distancias[vertice] + 1
 padres[vecino] = vertice

 return {
 'recorrido': recorrido,
 'distancias': distancias,
 'padres': padres
 }

 def bfs_nivel(self, inicio, nivel_maximo=None):
 """BFS que muestra la exploración por niveles"""
 visitados = {inicio}
 cola = deque([(inicio, 0)]) # (nodo, nivel)
 niveles = {0: [inicio]}

 while cola:
 vertice, nivel = cola.popleft()

 if nivel_maximo and nivel >= nivel_maximo:
 continue

 for vecino in self.lista_adyacencia[vertice]:
 if vecino not in visitados:
 visitados.add(vecino)
 cola.append((vecino, nivel + 1))

 if nivel + 1 not in niveles:
 niveles[nivel + 1] = []
 niveles[nivel + 1].append(vecino)

 return niveles

 def camino_mas_corto(self, inicio, destino):
 """Encuentra el camino más corto entre dos nodos usando BFS"""
 if inicio not in self.lista_adyacencia or destino not in self.lista_adyacencia:
 return None

 visitados = {inicio}
 cola = deque([inicio])
 padres = {inicio: None}

 while cola:
 vertice = cola.popleft()

 if vertice == destino:
 # Reconstruir camino
 camino = []
 actual = destino
 while actual is not None:
 camino.append(actual)
 actual = padres[actual]
 return list(reversed(camino))

 for vecino in self.lista_adyacencia[vertice]:
 if vecino not in visitados:
 visitados.add(vecino)
 cola.append(vecino)
 padres[vecino] = vertice

 return None # No hay camino

 def componentes_conexas(self):
 """Encuentra todas las componentes conexas del grafo"""
 visitados = set()
 componentes = []

 for vertice in self.lista_adyacencia:
 if vertice not in visitados:
 # Hacer BFS desde este vértice
 componente = []
 cola = deque([vertice])
 visitados.add(vertice)

 while cola:
 actual = cola.popleft()
 componente.append(actual)

 for vecino in self.lista_adyacencia[actual]:
 if vecino not in visitados:
 visitados.add(vecino)
 cola.append(vecino)

 componentes.append(componente)

 return componentes

 def es_bipartito(self):
 """Verifica si el grafo es bipartito usando BFS"""
 if not self.lista_adyacencia:
 return True, {}

 color = {} # 0 y 1 para dos colores

 for inicio in self.lista_adyacencia:
 if inicio not in color:
 cola = deque([inicio])
 color[inicio] = 0

 while cola:
 vertice = cola.popleft()

 for vecino in self.lista_adyacencia[vertice]:
 if vecino not in color:
 color[vecino] = 1 - color[vertice] # Color opuesto
 cola.append(vecino)
 elif color[vecino] == color[vertice]:
 return False, None

 return True, color

 def imprimir_grafo(self):
 """Imprime el grafo de forma legible"""
 for vertice, vecinos in self.lista_adyacencia.items():
 print(f"{vertice}: {', '.join(map(str, vecinos))}")

