## Implementación en JavaScript

javascript
class Grafo {
 constructor() {
 this.listaAdyacencia = new Map();
 }

 agregarVertice(vertice) {
 if (!this.listaAdyacencia.has(vertice)) {
 this.listaAdyacencia.set(vertice, []);
 }
 }

 agregarArista(u, v, dirigido = false) {
 this.agregarVertice(u);
 this.agregarVertice(v);

 this.listaAdyacencia.get(u).push(v);
 if (!dirigido) {
 this.listaAdyacencia.get(v).push(u);
 }
 }

 bfs(inicio) {
 const visitados = new Set();
 const cola = [inicio];
 const recorrido = [];
 const distancias = new Map([[inicio, 0]]);
 const padres = new Map([[inicio, null]]);

 visitados.add(inicio);

 while (cola.length > 0) {
 const vertice = cola.shift();
 recorrido.push(vertice);

 for (const vecino of this.listaAdyacencia.get(vertice) || []) {
 if (!visitados.has(vecino)) {
 visitados.add(vecino);
 cola.push(vecino);
 distancias.set(vecino, distancias.get(vertice) + 1);
 padres.set(vecino, vertice);
 }
 }
 }

 return { recorrido, distancias, padres };
 }

 caminoMasCorto(inicio, destino) {
 if (!this.listaAdyacencia.has(inicio) || !this.listaAdyacencia.has(destino)) {
 return null;
 }

 const visitados = new Set([inicio]);
 const cola = [[inicio, [inicio]]];

 while (cola.length > 0) {
 const [vertice, camino] = cola.shift();

 if (vertice === destino) {
 return camino;
 }

 for (const vecino of this.listaAdyacencia.get(vertice) || []) {
 if (!visitados.has(vecino)) {
 visitados.add(vecino);
 cola.push([vecino, [...camino, vecino]]);
 }
 }
 }

 return null;
 }
}


