El algoritmo de Dijkstra encuentra las distancias más cortas desde un nodo origen a todos los demás nodos en un grafo con pesos no negativos. Es como tener un mapa de carreteras y querer saber la ruta más corta desde tu ciudad a todas las demás.

Analogía: Imagina que eres un cartero y quieres encontrar la ruta más corta para entregar cartas. Dijkstra te dice, desde tu oficina, cuál es la distancia mínima a cada casa y por dónde debes ir.

## Implementación en Python

python
import heapq
from collections import defaultdict
import math

class GrafoDijkstra:
 def __init__(self):
 self.adyacencias = defaultdict(list)
 self.nodos = set()

 def agregar_arista(self, origen, destino, peso):
 """Agrega una arista con peso al grafo"""
 self.adyacencias[origen].append((destino, peso))
 self.nodos.add(origen)
 self.nodos.add(destino)

 def agregar_arista_bidireccional(self, origen, destino, peso):
 """Agrega aristas en ambos sentidos"""
 self.agregar_arista(origen, destino, peso)
 self.agregar_arista(destino, origen, peso)

 def dijkstra(self, origen):
 """
 Implementación clásica de Dijkstra usando heap
 Retorna distancias y caminos
 """
 # Inicializar distancias con infinito
 distancias = {nodo: math.inf for nodo in self.nodos}
 distancias[origen] = 0

 # Para reconstruir caminos
 anterior = {nodo: None for nodo in self.nodos}

 # Heap de (distancia, nodo)
 heap = [(0, origen)]
 visitados = set()

 print(f"Iniciando Dijkstra desde {origen}")

 while heap:
 dist_actual, nodo_actual = heapq.heappop(heap)

 # Si ya visitamos este nodo, continuar
 if nodo_actual in visitados:
 continue

 visitados.add(nodo_actual)
 print(f"\nVisitando {nodo_actual} (distancia {dist_actual})")

 # Explorar vecinos
 for vecino, peso in self.adyacencias[nodo_actual]:
 if vecino in visitados:
 continue

 nueva_distancia = dist_actual + peso

 if nueva_distancia < distancias[vecino]:
 distancias[vecino] = nueva_distancia
 anterior[vecino] = nodo_actual
 heapq.heappush(heap, (nueva_distancia, vecino))
 print(f" Actualizando {vecino} a distancia {nueva_distancia} (vía {nodo_actual})")

 return distancias, anterior

 def camino_mas_corto(self, origen, destino):
 """Encuentra el camino más corto entre dos nodos"""
 distancias, anterior = self.dijkstra(origen)

 if distancias[destino] == math.inf:
 return None, None

 # Reconstruir camino
 camino = []
 actual = destino
 while actual is not None:
 camino.append(actual)
 actual = anterior[actual]
 camino.reverse()

 return camino, distancias[destino]

 def dijkstra_con_parada(self, origen, destino):
 """Dijkstra optimizado para encontrar solo un destino"""
 distancias = {origen: 0}
 anterior = {origen: None}
 heap = [(0, origen)]
 visitados = set()

 while heap:
 dist_actual, nodo_actual = heapq.heappop(heap)

 if nodo_actual == destino:
 # Reconstruir camino
 camino = []
 actual = destino
 while actual is not None:
 camino.append(actual)
 actual = anterior[actual]
 camino.reverse()
 return camino, dist_actual

 if nodo_actual in visitados:
 continue

 visitados.add(nodo_actual)

 for vecino, peso in self.adyacencias[nodo_actual]:
 if vecino in visitados:
 continue

 nueva_distancia = dist_actual + peso

 if nueva_distancia < distancias.get(vecino, math.inf):
 distancias[vecino] = nueva_distancia
 anterior[vecino] = nodo_actual
 heapq.heappush(heap, (nueva_distancia, vecino))

 return None, None

 def distancias_a_todos(self, origen):
 """Versión simplificada que solo retorna distancias"""
 distancias = {nodo: math.inf for nodo in self.nodos}
 distancias[origen] = 0
 heap = [(0, origen)]

 while heap:
 dist_actual, nodo_actual = heapq.heappop(heap)

 if dist_actual > distancias[nodo_actual]:
 continue

 for vecino, peso in self.adyacencias[nodo_actual]:
 nueva_distancia = dist_actual + peso
 if nueva_distancia < distancias[vecino]:
 distancias[vecino] = nueva_distancia
 heapq.heappush(heap, (nueva_distancia, vecino))

 return distancias

 def imprimir_grafo(self):
 """Imprime el grafo de forma legible"""
 print("\nEstructura del grafo:")
 for nodo in sorted(self.nodos):
 for vecino, peso in self.adyacencias[nodo]:
 print(f" {nodo} --({peso})--> {vecino}")

# Ejemplo de uso
print("=== Ejemplo 1: Grafo simple ===")
grafo1 = GrafoDijkstra()

# Agregar aristas (origen, destino, peso)
aristas = [
 ('A', 'B', 4), ('A', 'C', 2),
 ('B', 'C', 1), ('B', 'D', 5),
 ('C', 'D', 8), ('C', 'E', 10),
 ('D', 'E', 2), ('D', 'F', 6),
 ('E', 'F', 3)
]

for o, d, p in aristas:
 grafo1.agregar_arista(o, d, p)

grafo1.imprimir_grafo()

# Encontrar caminos desde A
distancias, anteriores = grafo1.dijkstra('A')

print("\n=== Distancias desde A ===")
for nodo in sorted(distancias.keys()):
 print(f"Distancia a {nodo}: {distancias[nodo]}")

print("\n=== Caminos desde A ===")
for destino in ['B', 'C', 'D', 'E', 'F']:
 camino, distancia = grafo1.camino_mas_corto('A', destino)
 print(f"A → {destino}: {' → '.join(camino)} (distancia {distancia})")

print("\n=== Ejemplo 2: Grafo con bidireccional ===")
grafo2 = GrafoDijkstra()

# Grafo de ciudades
