## Implementación en Java

java
import java.util.*;

public class DijkstraAlgorithm {

 static class Arista {
 int destino;
 int peso;

 Arista(int destino, int peso) {
 this.destino = destino;
 this.peso = peso;
 }
 }

 static class Nodo implements Comparable<Nodo> {
 int id;
 int distancia;

 Nodo(int id, int distancia) {
 this.id = id;
 this.distancia = distancia;
 }

 @Override
 public int compareTo(Nodo otro) {
 return Integer.compare(this.distancia, otro.distancia);
 }
 }

 static class Grafo {
 private Map<Integer, List<Arista>> adyacencias;
 private Set<Integer> nodos;

 public Grafo() {
 adyacencias = new HashMap<>();
 nodos = new HashSet<>();
 }

 public void agregarArista(int origen, int destino, int peso) {
 adyacencias.computeIfAbsent(origen, k -> new ArrayList<>()).add(new Arista(destino, peso));
 nodos.add(origen);
 nodos.add(destino);
 }

 public void agregarAristaBidireccional(int origen, int destino, int peso) {
 agregarArista(origen, destino, peso);
 agregarArista(destino, origen, peso);
 }

 public Map<Integer, Integer> dijkstra(int origen) {
 Map<Integer, Integer> distancias = new HashMap<>();
 for (int nodo : nodos) {
 distancias.put(nodo, Integer.MAX_VALUE);
 }
 distancias.put(origen, 0);

 PriorityQueue<Nodo> heap = new PriorityQueue<>();
 heap.offer(new Nodo(origen, 0));

 Set<Integer> visitados = new HashSet<>();

 while (!heap.isEmpty()) {
 Nodo actual = heap.poll();

 if (visitados.contains(actual.id)) {
 continue;
 }

 visitados.add(actual.id);

 List<Arista> vecinos = adyacencias.getOrDefault(actual.id, new ArrayList<>());
 for (Arista arista : vecinos) {
 if (visitados.contains(arista.destino)) {
 continue;
 }

 int nuevaDistancia = actual.distancia + arista.peso;
 if (nuevaDistancia < distancias.get(arista.destino)) {
 distancias.put(arista.destino, nuevaDistancia);
 heap.offer(new Nodo(arista.destino, nuevaDistancia));
 }
 }
 }

 return distancias;
 }

 public List<Integer> caminoMasCorto(int origen, int destino) {
 Map<Integer, Integer> distancias = new HashMap<>();
 Map<Integer, Integer> anterior = new HashMap<>();

 for (int nodo : nodos) {
 distancias.put(nodo, Integer.MAX_VALUE);
 }
 distancias.put(origen, 0);
 anterior.put(origen, null);

 PriorityQueue<Nodo> heap = new PriorityQueue<>();
 heap.offer(new Nodo(origen, 0));

 Set<Integer> visitados = new HashSet<>();

 while (!heap.isEmpty()) {
 Nodo actual = heap.poll();

 if (actual.id == destino) {
 // Reconstruir camino
 List<Integer> camino = new ArrayList<>();
 int nodo = destino;
 while (nodo != origen) {
 camino.add(0, nodo);
 nodo = anterior.get(nodo);
 }
 camino.add(0, origen);
 return camino;
 }

 if (visitados.contains(actual.id)) {
 continue;
 }

 visitados.add(actual.id);

 List<Arista> vecinos = adyacencias.getOrDefault(actual.id, new ArrayList<>());
 for (Arista arista : vecinos) {
 if (visitados.contains(arista.destino)) {
 continue;
 }

 int nuevaDistancia = actual.distancia + arista.peso;
 if (nuevaDistancia < distancias.get(arista.destino)) {
 distancias.put(arista.destino, nuevaDistancia);
 anterior.put(arista.destino, actual.id);
 heap.offer(new Nodo(arista.destino, nuevaDistancia));
 }
 }
 }

 return null; // No hay camino
 }
 }

 public static void main(String[] args) {
 Grafo grafo = new Grafo();

 // Agregar aristas
 grafo.agregarAristaBidireccional(0, 1, 4);
 grafo.agregarAristaBidireccional(0, 7, 8);
 grafo.agregarAristaBidireccional(1, 2, 8);
 grafo.agregarAristaBidireccional(1, 7, 11);
 grafo.agregarAristaBidireccional(2, 3, 7);
 grafo.agregarAristaBidireccional(2, 5, 4);
 grafo.agregarAristaBidireccional(2, 8, 2);
 grafo.agregarAristaBidireccional(3, 4, 9);
 grafo.agregarAristaBidireccional(3, 5, 14);
 grafo.agregarAristaBidireccional(4, 5, 10);
 grafo.agregarAristaBidireccional(5, 6, 2);
 grafo.agregarAristaBidireccional(6, 7, 1);
 grafo.agregarAristaBidireccional(6, 8, 6);
 grafo.agregarAristaBidireccional(7, 8, 7);

 // Encontrar distancias desde el nodo 0
 Map<Integer, Integer> distancias = grafo.dijkstra(0);

 System.out.println("Distancias desde el nodo 0:");
 for (Map.Entry<Integer, Integer> entry : distancias.entrySet()) {
 System.out.println(" Nodo " + entry.getKey() + ": " + entry.getValue());
 }

 // Encontrar camino específico
 List<Integer> camino = grafo.caminoMasCorto(0, 4);
 System.out.println("\nCamino más corto de 0 a 4: " + camino);
 }
}


## Implementación en JavaScript

javascript
class GrafoDijkstra {
 constructor() {
 this.adyacencias = new Map();
 this.nodos = new Set();
 }

 agregarArista(origen, destino, peso) {
 if (!this.adyacencias.has(origen)) {
 this.adyacencias.set(origen, []);
 }
 this.adyacencias.get(origen).push({ destino, peso });
 this.nodos.add(origen);
 this.nodos.add(destino);
 }

 agregarAristaBidireccional(origen, destino, peso) {
 this.agregarArista(origen, destino, peso);
 this.agregarArista(destino, origen, peso);
 }

 dijkstra(origen) {
 const distancias = new Map();
 const anteriores = new Map();
 const heap = [];
 const visitados = new Set();

 // Inicializar distancias
 for (const nodo of this.nodos) {
 distancias.set(nodo, Infinity);
 }
 distancias.set(origen, 0);
 anteriores.set(origen, null);

 heap.push({ nodo: origen, distancia: 0 });

 while (heap.length > 0) {
 // Obtener el nodo con menor distancia
 heap.sort((a, b) => a.distancia - b.distancia);
 const { nodo: nodoActual, distancia: distActual } = heap.shift();

 if (visitados.has(nodoActual)) continue;
 visitados.add(nodoActual);

 const vecinos = this.adyacencias.get(nodoActual) || [];
 for (const { destino, peso } of vecinos) {
 if (visitados.has(destino)) continue;

 const nuevaDistancia = distActual + peso;
 if (nuevaDistancia < distancias.get(destino)) {
 distancias.set(destino, nuevaDistancia);
 anteriores.set(destino, nodoActual);
 heap.push({ nodo: destino, distancia: nuevaDistancia });
 }
 }
 }

 return { distancias, anteriores };
 }

 caminoMasCorto(origen, destino) {
 const { distancias, anteriores } = this.dijkstra(origen);

 if (distancias.get(destino) === Infinity) {
 return null;
 }

 const camino = [];
 let actual = destino;
 while (actual !== null) {
 camino.unshift(actual);
 actual = anteriores.get(actual);
 }

 return {
 camino,
 distancia: distancias.get(destino)
 };
 }
}


