function isHappy(n) {
    let slow = n, fast = n;
    do {
        slow = getNext(slow);
        fast = getNext(getNext(fast));
    } while (fast !== 1 && slow !== fast);
    return fast === 1;
}
function getNext(n) { /* suma cuadrados */ }
```

**Complejidad:**
