Gale-Shapley es directo con arrays de preferencias.

**Implementación completa:**
```cpp
vector<int> galeShapley(vector<vector<int>>& menPref, vector<vector<int>>& womenPref) {
    int n = menPref.size();
    vector<int> womenPartner(n, -1);
    vector<bool> menFree(n, true);
    while (count(menFree.begin(), menFree.end(), true) > 0) {
        int m;
        for (m = 0; m < n; m++) if (menFree[m]) break;
        for (int w : menPref[m]) {
            if (womenPartner[w] == -1) {
                womenPartner[w] = m;
                menFree[m] = false;
                break;
            } else {
                int m1 = womenPartner[w];
                if (find(womenPref[w].begin(), womenPref[w].end(), m) < find(womenPref[w].begin(), womenPref[w].end(), m1)) {
                    womenPartner[w] = m;
                    menFree[m] = false;
                    menFree[m1] = true;
                    break;
                }
            }
        }
    }
    return womenPartner;
}
```

**Complejidad:**
- Tiempo: O(n^2).
