```cpp
int dp[1 << N][N];
int solve(int mask, int u) {
    if (mask == (1 << N) - 1) return dist[u][0];
    if (dp[mask][u] != -1) return dp[mask][u];
    int ans = INF;
    for (int v = 0; v < N; v++) {
        if (!(mask & (1 << v))) ans = min(ans, dist[u][v] + solve(mask | (1 << v), v));
    }
    return dp[mask][u] = ans;
}
```

