```csharp
public List<T> ReservoirSample<T>(IEnumerable<T> stream, int k) {
    var reservoir = new List<T>();
    int i = 0;
    var rand = new Random();
    foreach (var item in stream) {
        if (i < k) reservoir.Add(item);
        else {
            int j = rand.Next(i + 1);
            if (j < k) reservoir[j] = item;
        }
        i++;
    }
    return reservoir;
}
```

