**Implementación completa:**
```go
func knapsack(W int, weights, values []int) int {
    n := len(weights)
    dp := make([]int, W+1)
    for i := 0; i < n; i++ {
        for w := W; w >= weights[i]; w-- {
            if dp[w-weights[i]]+values[i] > dp[w] {
                dp[w] = dp[w-weights[i]]+values[i]
            }
        }
    }
    return dp[W]
}
```

