int minimax(State state, int depth, bool isMax) {
    if (terminal(state)) return score(state);
    if (isMax) {
        int best = -INF;
        for (auto move : moves(state)) best = max(best, minimax(state, depth+1, false));
        return best;
    } else {
        int best = INF;
        for (auto move : moves(state)) best = min(best, minimax(state, depth+1, true));
        return best;
    }
}
```

**Complejidad:**
